def fix_cure_base_topics():
    """Rewrite ungated topic* / Recovery_* header lines in cure.json to Вы."""
    path = ROOT / "assets/Code/dialoguesHarvey.json"
    # skip - handle cure separately
    path = ROOT / "assets/Code/dialoguesHarveyCure.json"
    content = path.read_text(encoding="utf-8")

    # Add When 0,1,2 to first block
    old = '"Target": "Characters/Dialogue/Harvey",\n            "Entries": {\n                // ================== ДИАЛОГИ НАЧАЛА ЛЕЧЕНИЯ'
    new = '"Target": "Characters/Dialogue/Harvey",\n            "When": {\n                "Hearts:Harvey": "0,1,2"\n            },\n            "Entries": {\n                // ================== ДИАЛОГИ НАЧАЛА ЛЕЧЕНИЯ'
    if old in content:
        content = content.replace(old, new, 1)
    else:
        print("WARN cure: could not add When to base block")

    topic_vous = {
        "topicHarvey_EscalatedCare": "%Харви серьёзно смотрит на Вас.#$b#Состояние требует более интенсивного лечения. Остаётесь под медицинским наблюдением до стабилизации.$a#%Он готовит оборудование.",
        "topicHarvey_NightRound": "%Харви тихо входит.#$b#Проверю показатели. Если разбужу — это по протоколу.$0#%Он аккуратно проверяет состояние.",
        "topicStartTreatment": "%Харви осматривает Вас.#$b#Вижу, что нужна помощь. Сейчас проведу осмотр и назначу лечение.$0#%Он готовит инструменты.",
        "topicHurtCured": "%Харви снимает повязку.#$b#Заживление хорошее. Работайте в перчатках. При покраснении — на осмотр.$0#%Он напоминает о профилактике.",
        "topicBadlyHurtCured": "%Харви проверяет место травмы.#$b#Зажило. Соблюдайте режим. При слабости или боли — сразу в клинику.$0#%Он даёт рекомендации.",
        "topicTreatmentCompleted": "Лечение завершено.$0#$b#Надеюсь, самочувствие лучше — и будете осторожнее.$0#$b#При возврате симптомов — без отлагательств.$0",
        "topicPreventiveCare": "Рекомендую профилактику — меньше травм, больше сил.$l",
        "buffAntibioticsTreatment": "Антибиотики действуют.$0#$b#Курс нельзя прерывать.$a#$b#Даже если стало лучше — до конца по схеме.$0#$b#Иначе риск осложнений.$a",
        "Treat_Hurt_Before1": "Покажите, где болит.$0#$b#Обработаю и наложу повязку. Щадящий режим до следующего осмотра.$0",
    }

    for key, val in topic_vous.items():
        escaped_val = val.replace("\\", "\\\\").replace('"', '\\"')
        pattern = rf'(                "{re.escape(key)}": ")(?:[^"\\]|\\.)*(")'
        content, n = re.subn(pattern, rf"\1{escaped_val}\2", content, count=1)
        if n == 0:
            print(f"WARN cure topic: {key}")

    path.write_text(content, encoding="utf-8")
    print("dialoguesHarveyCure.json base topics: OK")


